26	  const cursedSurcharge = item.cursed ? base * CURSED_SURCHARGE_RATE : 0;
27	  const enchantmentSurcharge = item.enchantment >= 5 ? base * 0.3 : 0;
28	  return base + cursedSurcharge + enchantmentSurcharge;
