39	
40	  const componentCounts: Record<string, number> = {};
41	  for (const item of components) {
42	    componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
43	  }
44	
45	  const componentTotal = Object.values(componentCounts).reduce(
46	    (sum, count) => sum + componentGroupPremium(count),
47	    0,
48	  );
49	
50	  return mainBaseTotal + componentTotal;
51	};
52	
53	const calculateItemLevelSurcharges = (items: any[]): number => {
54	  const mainItems = items.filter((item) => !isComponent(item));
55	  return mainItems.reduce((sum, item) => {
56	    const base = MAIN_ITEM_PREMIUMS[item.type] ?? 0;
57	    const cursedSurcharge = item.cursed ? base * CURSED_SURCHARGE_RATE : 0;
58	    const enchantmentSurcharge = item.enchantment >= 5 ? base * 0.3 : 0;
59	    return sum + cursedSurcharge + enchantmentSurcharge;
60	  }, 0);
61	};
